# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions, account_balances):
    updated_balances = {}
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        if account_id in account_balances:
            updated_balances[account_id] = account_balances[account_id] + amount
        else:
            updated_balances[account_id] = amount
    return updated_balances

# Example usage:
transactions = [
    {'account_id': 1, 'amount': 100},
    {'account_id': 2, 'amount': -50},
    {'account_id': 1, 'amount': -30}
]
initial_balances = {1: 200, 2: 100}
updated_balances = process_transactions(transactions, initial_balances)
print(updated_balances)  # Output: {1: 170, 2: 50}